import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Use StringBuilder to safely store the user input
        StringBuilder safeBuffer = new StringBuilder();
        safeBuffer.append(name);

        // Limit the output length to 10 characters to prevent buffer overflow
        String truncatedName = safeBuffer.length() > 10 ? safeBuffer.substring(0, 10) : safeBuffer.toString();

        System.out.println("Welcome, " + truncatedName);
    }
}

### Explanation:
취약유형: Buffer Overflow
